module RefModule (
    input clk,
    input rst,
    input load,
    input [6:0] d,
    output [6:0] q
);

    reg [6:0] unused_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            unused_q_reg <= 7'b0000000;
        else if (load)
            unused_q_reg <= d;
        else
            unused_q_reg <= unused_q_reg + 1;
    end

    assign q = unused_q_reg;

endmodule
